import React, { useEffect, useState } from 'react';
import './Sidebar.css';

const NAV = [
  { href: '#hero',     icon: '▶', label: 'Intro',     num: '01' },
  { href: '#work',     icon: '⊞', label: 'Work',      num: '02' },
  { href: '#clients',  icon: '◉', label: 'Clients',   num: '03' },
  { href: '#reel',     icon: '◈', label: 'Showreel',  num: '04' },
  { href: '#services', icon: '◻', label: 'Services',  num: '05' },
  { href: '#contact',  icon: '✉', label: 'Contact',   num: '06' },
];

const STATS = [
  { n: '2.5M+', l: 'Views Generated' },
  { n: '80+',   l: 'Projects Done' },
  { n: '4yr',   l: 'Experience' },
  { n: '30+',   l: 'Happy Clients' },
];

export default function Sidebar({ activeSection }) {
  const [tc, setTc] = useState('00:00:00:00');

  useEffect(() => {
    let frame = 0;
    const id = setInterval(() => {
      frame++;
      const f = frame % 24;
      const s = Math.floor(frame / 24) % 60;
      const m = Math.floor(frame / 1440) % 60;
      const h = Math.floor(frame / 86400);
      setTc(
        `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}:${String(f).padStart(2,'0')}`
      );
    }, 1000 / 24);
    return () => clearInterval(id);
  }, []);

  return (
    <aside className="sidebar">
      <div className="sb-signal" />

      <div className="sb-inner">
        <div className="sb-logo">Portfolio · 2025</div>

        {/* Avatar */}
        <div className="sb-avatar-wrap">
          <div className="sb-avatar">S</div>
          <span className="sb-online" />
        </div>

        <h1 className="sb-name">Saksham<br />Manchanda</h1>
        <p className="sb-handle">@saksham.edits</p>
        <p className="sb-location">
          <svg width="10" height="10" viewBox="0 0 10 10" fill="none" stroke="currentColor" strokeWidth="1.5">
            <circle cx="5" cy="4" r="2" />
            <path d="M5 9 C3 7 1 5.5 1 4a4 4 0 0 1 8 0c0 1.5-2 3-4 5z" />
          </svg>
          India
        </p>

        <p className="sb-bio">
          I craft <strong>cinematic stories</strong> that make creators and brands unforgettable —
          getting <strong>2.5M+ eyeballs</strong> on my clients' content.
        </p>

        {/* Stats */}
        <div className="sb-stats">
          {STATS.map((s) => (
            <div className="sb-stat" key={s.l}>
              <div className="sb-stat-n">{s.n}</div>
              <div className="sb-stat-l">{s.l}</div>
            </div>
          ))}
        </div>

        {/* Availability */}
        <div className="sb-avail">
          <span className="avail-dot" />
          Open to work
        </div>

        {/* Nav */}
        <nav className="sb-nav">
          {NAV.map((item) => (
            <a
              key={item.href}
              href={item.href}
              className={`sb-nav-item ${activeSection === item.href.slice(1) ? 'active' : ''}`}
            >
              <span className="sb-nav-icon">{item.icon}</span>
              {item.label}
              <span className="sb-nav-num">{item.num}</span>
            </a>
          ))}
        </nav>

        {/* Socials */}
        <div className="sb-socials">
          {['YT', 'IG', 'X', 'Vimeo'].map((s) => (
            <a href="#contact" className="sb-soc" key={s}>{s}</a>
          ))}
        </div>
      </div>

      {/* Footer */}
      <div className="sb-footer">
        <div className="vu-label">// Audio Level</div>
        <div className="vu-meter">
          {[...Array(8)].map((_, i) => (
            <div key={i} className={`vu-bar vu-${i}`} />
          ))}
        </div>
        <div className="sb-tc">
          <span>TC</span>
          <span className="tc-val">{tc}</span>
        </div>
      </div>
    </aside>
  );
}
